"use client";

import React, { useState, useEffect } from "react";
import { Button } from "@/components/ui/button";
import { Menu, X, Wifi } from "lucide-react";
import Link from "next/link";
import Image from "next/image"; // Better for LCP/SEO
import { usePathname } from "next/navigation";
import { NavLink } from "./NavLink"; // Using our custom NavLink
import { cn } from "@/lib/utils";
const logo = '/images/logo.webp';

const Navbar: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [isInOfficePremises, setIsInOfficePremises] = useState(false);
  const pathname = usePathname();

  // Constants
  const OFFICE_LAT = 18.5921498;
  const OFFICE_LNG = 73.8001093;
  const OFFICE_RADIUS = 500; // meters

  const calculateDistance = (lat1: number, lon1: number, lat2: number, lon2: number): number => {
    const R = 6371e3;
    const φ1 = (lat1 * Math.PI) / 180;
    const φ2 = (lat2 * Math.PI) / 180;
    const Δφ = ((lat2 - lat1) * Math.PI) / 180;
    const Δλ = ((lon2 - lon1) * Math.PI) / 180;
    const a =
      Math.sin(Δφ / 2) * Math.sin(Δφ / 2) +
      Math.cos(φ1) * Math.cos(φ2) * Math.sin(Δλ / 2) * Math.sin(Δλ / 2);
    const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
    return R * c;
  };

  useEffect(() => {
    if (typeof window !== "undefined" && navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          const { latitude, longitude } = position.coords;
          const distance = calculateDistance(latitude, longitude, OFFICE_LAT, OFFICE_LNG);
          setIsInOfficePremises(distance <= OFFICE_RADIUS);
        },
        (error) => {
          if (error.code !== error.PERMISSION_DENIED) {
            console.warn(`Geolocation error[${error.code}]: ${error.message}`);
          }
          setIsInOfficePremises(false);
        }
      );
    }
  }, []);

  useEffect(() => {
    setIsOpen(false);
  }, [pathname]);

  const navLinks = [
    { name: "Home", href: "/#home" },
    { name: "Services", href: "/#services" },
    { name: "Booking", href: "/booking" },
    { name: "Managed Offices", href: "/managed-office-pune" },
    { name: "Pricing", href: "/#pricing" },
    { name: "Gallery", href: "/#gallery" },
    { name: "Locate Us", href: "/#locate" },
    { name: "Blogs", href: "/blogs" },
    { name: "Community", href: "/community" },
  ];

  return (
    <header className="fixed top-0 left-0 right-0 z-50 bg-background/95 backdrop-blur-sm border-b border-border">
      <nav className="container mx-auto px-4" aria-label="Main navigation">
        <div className="flex items-center justify-between h-20"> {/* Increased height for better branding */}
          <div className="flex-shrink-0">
            <Link href="/#home" className="block outline-none" aria-label="The Living Desk Home">
              <Image
                src={logo}
                alt="The Living Desk - Premium Coworking Space in Pune"
                width={180}
                height={50}
                priority // Ensures logo loads immediately (SEO/LCP)
                className="h-12 w-auto object-contain"
              />
            </Link>
          </div>

          {/* Desktop Navigation */}
          <div className="hidden xl:flex items-center space-x-6">
            <ul className="flex items-center space-x-6 list-none">
              {navLinks.map((link) => (
                <li key={link.name}>
                  <NavLink
                    to={link.href}
                    activeClassName="text-primary font-semibold"
                    className="text-sm font-medium text-muted-foreground transition-colors hover:text-primary"
                  >
                    {link.name}
                  </NavLink>
                </li>
              ))}

              {isInOfficePremises && (
                <li>
                  <NavLink to="/wifi" activeClassName="text-primary" className="flex items-center gap-1 text-sm font-medium text-muted-foreground hover:text-primary">
                    <Wifi className="w-4 h-4" /> Wifi
                  </NavLink>
                </li>
              )}
            </ul>

            <div className="flex items-center gap-4 ml-6 pl-6 border-l border-border">
              <NavLink to="/#contact" className="text-sm font-medium text-muted-foreground hover:text-primary">
                Contact
              </NavLink>
              <Button asChild size="sm">
                <Link href="/#contact">Get Started</Link>
              </Button>
            </div>
          </div>

          {/* Mobile Menu Button */}
          <div className="xl:hidden">
            <button
              type="button"
              onClick={() => setIsOpen(!isOpen)}
              className="p-2 text-foreground focus:ring-2 focus:ring-primary rounded-md"
              aria-expanded={isOpen}
              aria-label="Toggle navigation menu"
            >
              {isOpen ? <X size={28} /> : <Menu size={28} />}
            </button>
          </div>
        </div>

        {/* Mobile Navigation */}
        <div className={cn(
          "xl:hidden overflow-hidden transition-all duration-300 ease-in-out",
          isOpen ? "max-h-[80vh] pb-8 opacity-100" : "max-h-0 opacity-0"
        )}>
          <ul className="flex flex-col space-y-4 pt-4 list-none border-t border-border">
            {navLinks.map((link) => (
              <li key={link.name}>
                <Link
                  href={link.href}
                  onClick={() => setIsOpen(false)}
                  className="block text-lg font-medium text-foreground hover:text-primary"
                >
                  {link.name}
                </Link>
              </li>
            ))}

            {isInOfficePremises && (
              <li>
                <Link href="/wifi" onClick={() => setIsOpen(false)} className="flex items-center gap-2 text-lg font-medium text-primary">
                  <Wifi className="w-5 h-5" /> Access Wifi
                </Link>
              </li>
            )}

            <li className="pt-4">
              <Button asChild className="w-full text-lg h-12">
                <Link href="/#contact" onClick={() => setIsOpen(false)}>Get Started</Link>
              </Button>
            </li>
          </ul>
        </div>
      </nav>
    </header>
  );
};

export default Navbar;